    int seg_idx = static_cast<int>(block_idx >> SEG_SHIFT);
    int slot = static_cast<int>(block_idx & (SEG_SIZE - 1));
    auto *seg = segments[seg_idx].load(std::memory_order_acquire);
    if (!seg)
      return nullptr;
    return seg[slot].load(std::memory_order_acquire);
  }
};

